use soroban_sdk::testutils::Address as _;
use soroban_sdk::{contract, contractimpl, Address, Env, String, Vec, Symbol};
use sorosusu_contracts::lending_market::{InterSusuLendingMarket, InterSusuLendingMarketClient};
use sorosusu_contracts::liquidity_buffer::{LiquidityBuffer, LiquidityBufferClient};
use sorosusu_contracts::{SoroSusu, SoroSusuClient, UserStats, DataKey};
  #[contract] pub struct MockToken; #[contractimpl] impl MockToken {     pub fn mint(_env: Env, _to: Address, _amount: i128) {}     pub fn balance(_env: Env, _account: Address) -> i128 { 1000000_000_000 } }  #[test] fn test_lending_market_initialization() {     let env = Env::default();     env.mock_all_auths();     let admin = Address::generate(&env);     let contract_id = env.register_contract(None, InterSusuLendingMarket);     let client = InterSusuLendingMarketClient::new(&env, &contract_id);     client.init_lending_market(&admin);     let config = client.get_lending_market_config();     assert!(config.is_enabled); }  #[test] fn test_lending_pool_creation() {     let env = Env::default();     env.mock_all_auths();     let admin = Address::generate(&env);     let creator = Address::generate(&env);     let contract_id = env.register_contract(None, InterSusuLendingMarket);     let client = InterSusuLendingMarketClient::new(&env, &contract_id);     client.init_lending_market(&admin);     let tok = Address::generate(&env);     let lender_circle_id = client.create_circle(&creator, &1000_000_000, &5, &tok, &86400, &100i128);     let borrower_circle_id = client.create_circle(&creator, &1000_000_000, &5, &tok, &86400, &100i128);     client.create_lending_pool(&lender_circle_id, &borrower_circle_id, &500_000_000); }
